mapper.sql:
SELECT ROW_NUMBER() OVER (ORDER BY REG_DTTM DESC, DSCS_ID DESC) LINE_NO , COUNT(*) OVER() TOTAL_CNT , DSCS_ID , DSCS_GRP_ID , DSCS_GBNCD , DSCS_UNIT_TYCD , EVL_SCR_TYCD , DSCS_TTL , DSCS_CTS , DSCS_SDTTM , DSCS_EDTTM , DVCLS_ID , LRN_GRP_ID , DELYN , OATCL_INQYN , OKNOK_CFGYN , OKNOKRT_OYN , OKNOK_MODYN , MLT_OPNN_REGYN , OKNOK_RGTR_OYN , CMNT_RSPNS_REQYN , MRK_RFLTYN , MRK_OYN , RGTR_ID , REG_DTTM , MDFR_ID , MOD_DTTM , SBJCT_ID FROM TB_LMS_DSCS WHERE 1 = 1 AND DELYN = 'N'
AND SBJCT_ID = #{sbjctId}
AND DSCS_GBNCD = #{dscsGbncd}
AND DSCS_UNIT_TYCD = #{dscsUnitTycd}
AND EVL_SCR_TYCD = #{evlScrTycd}
AND DSCS_TTL LIKE FN_LIKE_VAL(#{dscsTtl})
AND TO_DATE(DSCS_SDTTM, 'YYYYMMDDHH24MISS') BETWEEN TO_DATE(#{dscsSdttm}, 'YYYYMMDDHH24MISS') AND TO_DATE(#{dscsEdttm}, 'YYYYMMDDHH24MISS')
ORDER BY REG_DTTM DESC, DSCS_ID DESC

mapper.update:
/*
    SQL ID : ForumDAO.updateForum
    설명 : 토론수정
*/
UPDATE TB_LMS_DSCS
SET MDFR_ID = NVL(#{mdfrId}, #{rgtrId})
  , MOD_DTTM = FN_DTTM()

  , DSCS_GRP_ID = #{dscsGrpId}


  , DSCS_GBNCD = #{dscsGbncd}


  , DSCS_UNIT_TYCD = #{dscsUnitTycd}


  , EVL_SCR_TYCD = #{evlScrTycd}


  , DSCS_TTL = #{dscsTtl}


  , DSCS_CTS = #{dscsCts}


  , DSCS_SDTTM = #{dscsSdttm}


  , DSCS_EDTTM = #{dscsEdttm}


  , DVCLS_ID = #{dvclsId}


  , LRN_GRP_ID = #{lrnGrpId}


  , DELYN = #{delyn}


  , OATCL_INQYN = #{oatclInqyn}


  , OKNOK_CFGYN = #{oknokCfgyn}


  , OKNOKRT_OYN = #{oknokrtOyn}


  , OKNOK_MODYN = #{oknokModyn}


  , MLT_OPNN_REGYN = #{mltOpnnRegyn}


  , OKNOK_RGTR_OYN = #{oknokRgtrOyn}


  , CMNT_RSPNS_REQYN = #{cmntRspnsReqyn}


  , MRK_RFLTYN = #{mrkRfltyn}


  , MRK_OYN = #{mrkOyn}


  , SBJCT_ID = #{sbjctId}

WHERE DSCS_ID = #{dscsId}
